import timeimport requestsimport pandas as pdimport mplfinance as mpfimport matplotlib.pyplot as pltimport matplotlib.backends.backend_agg as aggimport pygame# -----------------------------# API / DATA# -----------------------------def fetch_data(days):    """    Fetch Bitcoin OHLC data from the CoinGecko API.    Returns a pandas DataFrame with Open, High, Low, Close and Volume columns.    """    print(f"Fetching Bitcoin data for: {days} days")    url = (        "https://api.coingecko.com/api/v3/coins/bitcoin/ohlc"        f"?vs_currency=usd&days={days}"    )    try:        timeout_seconds = 20 if days == "max" else 8                headers = {            "User-Agent": "bitcoin-price-chart-visualiser/1.0"            }        response = requests.get(url, headers=headers, timeout=timeout_seconds)        response.raise_for_status()        data = response.json()        df = pd.DataFrame(            data,            columns=["timestamp", "Open", "High", "Low", "Close"]        )        df["timestamp"] = pd.to_datetime(df["timestamp"], unit="ms")        df.set_index("timestamp", inplace=True)        # CoinGecko OHLC endpoint does not provide volume.        # mplfinance expects this column, so we add it as a placeholder.        df["Volume"] = 0        print(f"Fetched {len(df)} rows")        return df    except requests.exceptions.RequestException as error:        print(f"API request failed: {error}")        return pd.DataFrame(columns=["Open", "High", "Low", "Close", "Volume"])    except Exception as error:        print(f"Data processing failed: {error}")        return pd.DataFrame(columns=["Open", "High", "Low", "Close", "Volume"])# -----------------------------# CHART DRAWING# -----------------------------def draw_graph(df, plot_type="candle", dark_mode=False):    """    Draw a financial chart using mplfinance and convert it into a Pygame surface.    """    if df.empty:        surface = pygame.Surface((800, 500))        surface.fill((240, 240, 240))        return surface    style = "nightclouds" if dark_mode else "charles"    fig, _ = mpf.plot(        df,        type=plot_type,        style=style,        returnfig=True,        figsize=(8, 5),        warn_too_much_data=100000,    )    canvas = agg.FigureCanvasAgg(fig)    canvas.draw()    renderer = canvas.get_renderer()    raw_data = renderer.buffer_rgba()    size = canvas.get_width_height()    surface = pygame.image.frombuffer(bytes(raw_data), size, "RGBA")    # Close the matplotlib figure to avoid memory build-up.    plt.close(fig)    return surface# -----------------------------# UI DRAWING# -----------------------------def draw_buttons(screen, buttons, button_color, text_color):    """    Draw the timeframe and dark mode buttons.    """    font = pygame.font.Font(None, 24)    for label, rect in buttons.items():        pygame.draw.rect(screen, button_color, rect, border_radius=5)        text = font.render(label, True, text_color)        text_rect = text.get_rect(center=rect.center)        screen.blit(text, text_rect)def draw_tooltip(screen, x, y, text, dark_mode):    """    Draw a tooltip showing date and price.    """    font = pygame.font.Font(None, 24)    tooltip_text_color = (255, 255, 255) if dark_mode else (0, 0, 0)    tooltip_background = (40, 40, 40) if dark_mode else (230, 230, 230)    text_surface = font.render(text, True, tooltip_text_color)    tooltip_rect = text_surface.get_rect(topleft=(x + 12, y + 12))    tooltip_rect.inflate_ip(12, 8)    pygame.draw.rect(screen, tooltip_background, tooltip_rect, border_radius=4)    screen.blit(text_surface, (tooltip_rect.x + 6, tooltip_rect.y + 4))# -----------------------------# MAIN PROGRAM# -----------------------------def main():    pygame.init()    # Window size. Easier to run in Spyder than fullscreen.    width = 1100    height = 700    screen = pygame.display.set_mode((width, height))    pygame.display.set_caption("Bitcoin Price Chart Visualiser")    light_mode_bg = (255, 255, 255)    dark_mode_bg = (0, 0, 0)    button_color = (0, 70, 180)    text_color = (255, 255, 255)    dark_mode = False    background_color = light_mode_bg    button_width = 100    button_height = 35    button_gap = 10    buttons = {        "1 Day": pygame.Rect(            button_gap,            height - button_height - button_gap,            button_width,            button_height,        ),        "1 Week": pygame.Rect(            button_gap * 2 + button_width,            height - button_height - button_gap,            button_width,            button_height,        ),        "1 Month": pygame.Rect(            button_gap * 3 + button_width * 2,            height - button_height - button_gap,            button_width,            button_height,        ),        "1 Year": pygame.Rect(            button_gap * 4 + button_width * 3,            height - button_height - button_gap,            button_width,            button_height,        ),        "Max": pygame.Rect(            button_gap * 5 + button_width * 4,            height - button_height - button_gap,            button_width,            button_height,        ),        "Dark Mode": pygame.Rect(            button_gap * 6 + button_width * 5,            height - button_height - button_gap,            button_width + 25,            button_height,        ),    }    timeframe_map = {        "1 Day": 1,        "1 Week": 7,        "1 Month": 30,        "1 Year": 365,        "Max": "max",    }    data_cache = {}    graph_cache = {}    def get_graph_for_timeframe(label):        """        Load data and graph for selected timeframe.        Uses caching so the app does not keep repeating API calls.        """        days = timeframe_map.get(label, 30)        if label not in data_cache:            data_cache[label] = fetch_data(days)        plot_type = "line" if label == "Max" else "candle"        cache_key = (label, dark_mode)        if cache_key not in graph_cache:            graph_cache[cache_key] = draw_graph(                data_cache[label],                plot_type=plot_type,                dark_mode=dark_mode,            )        return graph_cache[cache_key]    timeframe_label = "1 Day"    graph = get_graph_for_timeframe(timeframe_label)    clock = pygame.time.Clock()    running = True    while running:        try:            for event in pygame.event.get():                if event.type == pygame.QUIT:                    running = False                elif event.type == pygame.KEYDOWN:                    if event.key == pygame.K_ESCAPE:                        running = False                    # Press R to refresh the current timeframe.                    elif event.key == pygame.K_r:                        print("Refreshing data...")                        data_cache.pop(timeframe_label, None)                        graph_cache.clear()                        graph = get_graph_for_timeframe(timeframe_label)                elif event.type == pygame.MOUSEBUTTONDOWN:                    mouse_pos = pygame.mouse.get_pos()                    for label, rect in buttons.items():                        if rect.collidepoint(mouse_pos):                            if label == "Dark Mode":                                dark_mode = not dark_mode                                background_color = (                                    dark_mode_bg if dark_mode else light_mode_bg                                )                                graph = get_graph_for_timeframe(timeframe_label)                            else:                                timeframe_label = label                                graph = get_graph_for_timeframe(timeframe_label)            screen.fill(background_color)            graph_rect = graph.get_rect(center=(width // 2, height // 2 - 40))            screen.blit(graph, graph_rect.topleft)            draw_buttons(screen, buttons, button_color, text_color)            # Tooltip            mouse_x, mouse_y = pygame.mouse.get_pos()            if (                graph_rect.left <= mouse_x <= graph_rect.right                and graph_rect.top <= mouse_y <= graph_rect.bottom                and timeframe_label in data_cache                and not data_cache[timeframe_label].empty            ):                df = data_cache[timeframe_label]                relative_x = mouse_x - graph_rect.left                date_index = min(                    max(0, relative_x * len(df) // graph_rect.width),                    len(df) - 1,                )                date = df.index[date_index]                price = df["Close"].iloc[date_index]                tooltip_text = f"{date.strftime('%Y-%m-%d %H:%M')}: ${price:.2f}"                draw_tooltip(                    screen,                    mouse_x,                    mouse_y,                    tooltip_text,                    dark_mode,                )            pygame.display.flip()            clock.tick(30)        except Exception as error:            print(f"Unexpected error: {error}")            running = False    pygame.quit()    plt.close("all")if __name__ == "__main__":    main()